            month_key = date_obj.strftime('%Y-%m')
            month_name = date_obj.strftime('%B')
            month_counts[month_key] = month_counts.get(month_key, {'name': month_name, 'count': 0})
            month_counts[month_key]['count'] += 1
        except:
            pass

result_details = {
    'total_related_cases': len(related_cases),
    'cases_per_month': [],
    'month_with_most': None,
    'max_count': 0
}

