    result_details['cases_per_month'].append({
        'month': data['name'],
        'key': month_key,
        'count': data['count']
    })

if month_counts:
    max_month = max(month_counts.items(), key=lambda x: x[1]['count'])
    result_details['month_with_most'] = max_month[1]['name']
    result_details['max_count'] = max_month[1]['count']

print('__RESULT__:')
print(json.dumps(result_details))"}

